const body = items[0].json.body;
if (!body || !body.events || body.events.length === 0) {
  return [];
}

const event = body.events[0];
const userId = event.source.userId;
const eventType = event.type;
const replyToken = event.replyToken;

let messageText = '';
let postbackData = '';
let postbackParams = {};

if (eventType === 'message' && event.message.type === 'text') {
  messageText = event.message.text.trim();
} else if (eventType === 'postback') {
  postbackData = event.postback.data;
  postbackParams = event.postback.params || {};
}

return [{
  json: {
    userId,
    eventType,
    replyToken,
    messageText,
    postbackData,
    postbackParams
  }
}];

const input = $('PG: Get Employee & Session').first().json;
const parsedEvent = $('Parse LINE Event').first().json;
const userId = parsedEvent.userId;
const replyToken = parsedEvent.replyToken;
const messageText = parsedEvent.messageText ? parsedEvent.messageText.trim() : '';
const cleanText = messageText.toLowerCase();

// Get Ollama NLP output
const ollamaRes = $('Ollama: Parse Intent').first().json.response;
let nlp = { intent: 'general_chat', leave_type: null, start_date: null, end_date: null, days: null, reason: null, employee_code: null };
try {
  let cleanRes = ollamaRes.trim();
  if (cleanRes.startsWith('```json')) {
    cleanRes = cleanRes.slice(7);
  }
  if (cleanRes.startsWith('```')) {
    cleanRes = cleanRes.slice(3);
  }
  if (cleanRes.endsWith('```')) {
    cleanRes = cleanRes.slice(0, -3);
  }
  nlp = JSON.parse(cleanRes.trim());
} catch (e) {
  console.error('Failed to parse Ollama JSON:', e);
}

let responseType = 'direct_reply';
let replyMessages = [];
let sql = '';
let params = [];

// Helper functions for date parsing and days calculation
function parseDate(text, baseDate = null) {
  const clean = text.trim().toLowerCase();
  const today = new Date(new Date().getTime() + (7 * 60 * 60 * 1000));
  if (clean === 'วันนี้') {
    return today.toISOString().split('T')[0];
  }
  if (clean === 'พรุ่งนี้') {
    const tomorrow = new Date(today.getTime() + (24 * 60 * 60 * 1000));
    return tomorrow.toISOString().split('T')[0];
  }
  if (baseDate && clean.includes('วัน')) {
    const match = clean.match(/^(\d+)\s*วัน$/);
    if (match) {
      const numDays = parseInt(match[1]);
      if (numDays > 0) {
        const start = new Date(baseDate);
        const end = new Date(start.getTime() + ((numDays - 1) * 24 * 60 * 60 * 1000));
        return end.toISOString().split('T')[0];
      }
    }
  }
  const dateRegex = /^(\d{4})-(\d{2})-(\d{2})$/;
  if (dateRegex.test(clean)) {
    const d = new Date(clean);
    if (!isNaN(d.getTime())) {
      return clean;
    }
  }
  return null;
}

function calculateDays(start, end) {
  const s = new Date(start);
  const e = new Date(end);
  const diffTime = e.getTime() - s.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
  return diffDays > 0 ? diffDays : 1;
}

function getLeaveTypeThai(type) {
  if (type === 'sick') return '🤒 ลาป่วย';
  if (type === 'annual') return '✈️ ลาพักร้อน';
  if (type === 'personal') return 'ลากิจ';
  return type;
}

function getRemainingDays(type) {
  if (type === 'sick') return input.total_sick_leave - input.used_sick_leave;
  if (type === 'annual') return input.total_annual_leave - input.used_annual_leave;
  if (type === 'personal') return input.total_personal_leave - input.used_personal_leave;
  return 0;
}

// 1. Handlers for unregistered users
if (!input.employee_id && !messageText.startsWith('/switch ')) {
  responseType = 'direct_reply';
  replyMessages = [{
    "type": "text",
    "text": "⚠️ คุณยังไม่ได้ลงทะเบียนในระบบบอท HR\nโปรดพิมพ์คำสั่งสลับบัญชีเพื่อทดสอบ เช่น:\n/switch EMP001 (เพื่อสวมบทบาท สมชาย)"
  }];
}
// 2. Handler for /switch <employee_code>
else if (messageText.startsWith('/switch ') || (nlp.intent === 'switch_user' && nlp.employee_code)) {
  const code = (nlp.intent === 'switch_user' && nlp.employee_code) ? nlp.employee_code : messageText.replace('/switch ', '').trim().toUpperCase();
  responseType = 'execute_sql';

  sql = `
    -- Unbind previous bindings
    UPDATE employees SET line_user_id = NULL WHERE line_user_id = $1;
    -- Bind new employee
    UPDATE employees SET line_user_id = $1 WHERE employee_code = $2;
    -- Upsert session state
    INSERT INTO user_sessions (line_user_id, current_state, temp_data)
    VALUES ($1, 'idle', '{}'::jsonb)
    ON CONFLICT (line_user_id) DO UPDATE SET current_state = 'idle', temp_data = '{}'::jsonb;
  `;
  params = [userId, code];

  replyMessages = [{
    "type": "text",
    "text": `🔄 กำลังสลับบัญชีเป็นรหัสพนักงาน ${code}...\nกรุณารอสักครู่ (หากพิมพ์สำเร็จ บัญชี LINE นี้จะเปลี่ยนตัวตนทันที)`
  }];
}
// 3. User is registered - State Machine for Leave Request (Multi-turn Slot Filling)
else if (input.current_state && input.current_state !== 'idle') {
  const state = input.current_state;
  let tempData = input.temp_data || {};

  if (cleanText === 'ยกเลิก' || nlp.intent === 'general_chat' && cleanText === 'cancel') {
    responseType = 'execute_sql';
    sql = `UPDATE user_sessions SET current_state = 'idle', temp_data = '{}'::jsonb WHERE line_user_id = $1;`;
    params = [userId];
    replyMessages = [{
      "type": "text",
      "text": "❌ ยกเลิกการทำรายการเรียบร้อยแล้ว กลับสู่สถานะปกติ"
    }];
  }
  else if (state === 'awaiting_leave_type') {
    let leaveType = '';
    let leaveTypeThai = '';
    if (cleanText.includes('ป่วย') || cleanText === 'sick') {
      leaveType = 'sick';
      leaveTypeThai = '🤒 ลาป่วย';
    } else if (cleanText.includes('พักร้อน') || cleanText === 'annual') {
      leaveType = 'annual';
      leaveTypeThai = '✈️ ลาพักร้อน';
    } else if (cleanText.includes('กิจ') || cleanText === 'personal') {
      leaveType = 'personal';
      leaveTypeThai = 'ลากิจ';
    }

    if (!leaveType) {
      responseType = 'direct_reply';
      replyMessages = [{
        "type": "text",
        "text": "⚠️ ประเภทการลาไม่ถูกต้อง โปรดเลือกประเภทการลา:\n- พิมพ์ \"ลาป่วย\"\n- พิมพ์ \"ลาพักร้อน\"\n- พิมพ์ \"ลากิจ\"\n(หรือพิมพ์ \"ยกเลิก\" เพื่อออกจากการทำรายการ)"
      }];
    } else {
      const rem = getRemainingDays(leaveType);
      if (rem <= 0) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'idle', temp_data = '{}'::jsonb WHERE line_user_id = $1;`;
        params = [userId];
        replyMessages = [{
          "type": "text",
          "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากสิทธิ์วันลาหมดแล้ว\n\n- ประเภทการลา: ${leaveTypeThai}\n- คงเหลือ: 0 วัน`
        }];
      } else {
        tempData.leave_type = leaveType;
        tempData.leave_type_thai = leaveTypeThai;

      // Check next missing slot
      if (!tempData.start_date) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'awaiting_start_date', temp_data = $2::jsonb WHERE line_user_id = $1;`;
        params = [userId, JSON.stringify(tempData)];
        replyMessages = [{
          "type": "text",
          "text": `📋 ประเภทการลา: ${leaveTypeThai}\n\nโปรดระบุ "วันที่เริ่มลาหยุด" (เช่น 2026-06-25 หรือพิมพ์ วันนี้ / พรุ่งนี้)`
        }];
      } else if (!tempData.end_date) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'awaiting_end_date', temp_data = $2::jsonb WHERE line_user_id = $1;`;
        params = [userId, JSON.stringify(tempData)];
        replyMessages = [{
          "type": "text",
          "text": `📋 ประเภทการลา: ${leaveTypeThai}\n📅 วันที่เริ่มลา: ${tempData.start_date}\n\nโปรดระบุ "วันที่สิ้นสุด" (เช่น 2026-06-26)`
        }];
      } else if (!tempData.reason) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'awaiting_reason', temp_data = $2::jsonb WHERE line_user_id = $1;`;
        params = [userId, JSON.stringify(tempData)];
        replyMessages = [{
          "type": "text",
          "text": `📋 ประเภทการลา: ${leaveTypeThai}\n📅 ระยะเวลาลา: ${tempData.start_date} ถึง ${tempData.end_date} (${tempData.days} วัน)\n\nโปรดระบุ "เหตุผลการลา" (เช่น พักผ่อน / มีธุระ)`
        }];
      }
    }
  }
  else if (state === 'awaiting_start_date') {
    const startDate = parseDate(messageText);
    if (!startDate) {
      responseType = 'direct_reply';
      replyMessages = [{
        "type": "text",
        "text": "⚠️ วันที่เริ่มไม่ถูกต้อง โปรดระบุฟอร์แมต YYYY-MM-DD (เช่น 2026-06-25) หรือพิมพ์ \"วันนี้\" / \"พรุ่งนี้\""
      }];
    } else {
      tempData.start_date = startDate;

      // Check next missing slot
      if (!tempData.end_date) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'awaiting_end_date', temp_data = $2::jsonb WHERE line_user_id = $1;`;
        params = [userId, JSON.stringify(tempData)];
        replyMessages = [{
          "type": "text",
          "text": `📅 วันที่เริ่มลา: ${startDate}\n\nโปรดระบุ "วันที่สิ้นสุด" (เช่น 2026-06-26 หรือพิมพ์จำนวนวัน เช่น 2 วัน)`
        }];
      } else {
        const days = calculateDays(startDate, tempData.end_date);
        const rem = getRemainingDays(tempData.leave_type);
        if (days > rem) {
          responseType = 'execute_sql';
          sql = `UPDATE user_sessions SET current_state = 'idle', temp_data = '{}'::jsonb WHERE line_user_id = $1;`;
          params = [userId];
          replyMessages = [{
            "type": "text",
            "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากวันหยุดคงเหลือไม่พอ\n\n- ประเภทการลา: ${tempData.leave_type_thai}\n- จำนวนที่ขอ: ${days} วัน\n- คงเหลือ: ${rem} วัน\n\nระบบยกเลิกรายการโดยอัตโนมัติ`
          }];
        } else {
          tempData.days = days;
          if (!tempData.reason) {
            responseType = 'execute_sql';
            sql = `UPDATE user_sessions SET current_state = 'awaiting_reason', temp_data = $2::jsonb WHERE line_user_id = $1;`;
            params = [userId, JSON.stringify(tempData)];
            replyMessages = [{
              "type": "text",
              "text": `📅 ระยะเวลาลา: ${startDate} ถึง ${tempData.end_date} (${tempData.days} วัน)\n\nโปรดระบุ "เหตุผลการลา"`
            }];
          }
        }
      }
    }
  }
  else if (state === 'awaiting_end_date') {
    const endDate = parseDate(messageText, tempData.start_date);
    if (!endDate || endDate < tempData.start_date) {
      responseType = 'direct_reply';
      replyMessages = [{
        "type": "text",
        "text": "⚠️ วันที่สิ้นสุดไม่ถูกต้อง (ต้องไม่น้อยกว่าวันที่เริ่ม) โปรดระบุแบบ YYYY-MM-DD หรือพิมพ์จำนวนวัน เช่น 1 วัน"
      }];
    } else {
      const days = calculateDays(tempData.start_date, endDate);
      const rem = getRemainingDays(tempData.leave_type);
      if (days > rem) {
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = 'idle', temp_data = '{}'::jsonb WHERE line_user_id = $1;`;
        params = [userId];
        replyMessages = [{
          "type": "text",
          "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากวันหยุดคงเหลือไม่พอ\n\n- ประเภทการลา: ${tempData.leave_type_thai}\n- จำนวนที่ขอ: ${days} วัน\n- คงเหลือ: ${rem} วัน\n\nระบบยกเลิกรายการโดยอัตโนมัติ`
        }];
      } else {
        tempData.end_date = endDate;
        tempData.days = days;

        if (!tempData.reason) {
          responseType = 'execute_sql';
          sql = `UPDATE user_sessions SET current_state = 'awaiting_reason', temp_data = $2::jsonb WHERE line_user_id = $1;`;
          params = [userId, JSON.stringify(tempData)];
          replyMessages = [{
            "type": "text",
            "text": `📅 ระยะเวลาลา: ${tempData.start_date} ถึง ${endDate} (${days} วัน)\n\nโปรดระบุ "เหตุผลการลา"`
          }];
        }
      }
    }
  }
  else if (state === 'awaiting_reason') {
    const reason = messageText;
    tempData.reason = reason;

    const rem = getRemainingDays(tempData.leave_type);
    if (tempData.days > rem) {
      responseType = 'execute_sql';
      sql = `UPDATE user_sessions SET current_state = 'idle', temp_data = '{}'::jsonb WHERE line_user_id = $1;`;
      params = [userId];
      replyMessages = [{
        "type": "text",
        "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากวันหยุดคงเหลือไม่พอ\n\n- ประเภทการลา: ${tempData.leave_type_thai}\n- จำนวนที่ขอ: ${tempData.days} วัน\n- คงเหลือ: ${rem} วัน\n\nระบบยกเลิกรายการโดยอัตโนมัติ`
      }];
    } else {
      responseType = 'execute_sql';

      // Save to leave_requests and reset user session in a single transaction
      sql = `
        WITH new_leave AS (
          INSERT INTO leave_requests (employee_id, leave_type, start_date, end_date, days, reason, status)
          VALUES ($2::uuid, $3::text, $4::date, $5::date, $6::numeric, $7::text, 'pending')
          RETURNING id
        )
        UPDATE user_sessions 
        SET current_state = 'idle', temp_data = '{}'::jsonb 
        WHERE line_user_id = $1;
      `;
      params = [
        userId,
        input.employee_id,
        tempData.leave_type,
        tempData.start_date,
        tempData.end_date,
        tempData.days,
        reason
      ];

      replyMessages = [{
        "type": "text",
        "text": `✅ ส่งคำขอลาหยุดเรียบร้อยแล้ว!\n\n📋 รายละเอียดคำขอ:\n- ประเภท: ${tempData.leave_type_thai}\n- ระยะเวลา: ${tempData.start_date} ถึง ${tempData.end_date} (${tempData.days} วัน)\n- เหตุผล: ${reason}\n\nคำขอของคุณได้รับการบันทึกเข้าระบบแล้ว และกำลังรอการพิจารณาอนุมัติจากฝ่ายบุคคล (HR)`
      }];
    }
  }
}
// 4. NLP Smart Processing (When user is in 'idle' state)
else {
  if (nlp.intent === 'request_leave') {
    // LLM extracted a leave request! Let's check what variables are already present.
    let tempData = {
      leave_type: nlp.leave_type || null,
      leave_type_thai: nlp.leave_type ? getLeaveTypeThai(nlp.leave_type) : null,
      start_date: nlp.start_date || null,
      end_date: nlp.end_date || null,
      days: nlp.days || null,
      reason: nlp.reason || null
    };

    // If end_date is present but start_date is not, default start_date to today
    const today = new Date(new Date().getTime() + (7 * 60 * 60 * 1000)).toISOString().split('T')[0];
    if (tempData.end_date && !tempData.start_date) {
      tempData.start_date = today;
    }

    // If start_date is present but end_date is not:
    if (tempData.start_date && !tempData.end_date) {
      if (tempData.days) {
        // Calculate end_date = start_date + days - 1
        const start = new Date(tempData.start_date);
        const end = new Date(start.getTime() + ((tempData.days - 1) * 24 * 60 * 60 * 1000));
        tempData.end_date = end.toISOString().split('T')[0];
      } else {
        // Default end_date to start_date (1 day)
        tempData.end_date = tempData.start_date;
        tempData.days = 1;
      }
    }

    // Recalculate days if start and end are present
    if (tempData.start_date && tempData.end_date && !tempData.days) {
      tempData.days = calculateDays(tempData.start_date, tempData.end_date);
    }

    // Check if we have EVERYTHING to submit immediately
    if (tempData.leave_type && tempData.start_date && tempData.end_date && tempData.reason) {
      const rem = getRemainingDays(tempData.leave_type);
      if (tempData.days > rem) {
        responseType = 'direct_reply';
        replyMessages = [{
          "type": "text",
          "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากวันหยุดคงเหลือไม่พอ\n\n- ประเภทการลา: ${tempData.leave_type_thai}\n- จำนวนที่ขอ: ${tempData.days} วัน\n- คงเหลือ: ${rem} วัน`
        }];
      } else {
        // Submit immediately!
        responseType = 'execute_sql';
        sql = `
          INSERT INTO leave_requests (employee_id, leave_type, start_date, end_date, days, reason, status)
          VALUES ($2::uuid, $3::text, $4::date, $5::date, $6::numeric, $7::text, 'pending');
        `;
        params = [
          userId,
          input.employee_id,
          tempData.leave_type,
          tempData.start_date,
          tempData.end_date,
          tempData.days,
          tempData.reason
        ];

        replyMessages = [{
          "type": "text",
          "text": `✅ ส่งคำขอลาหยุดผ่านระบบ AI สำเร็จเรียบร้อยแล้ว!\n\n📋 รายละเอียดใบลา:\n- ประเภท: ${tempData.leave_type_thai}\n- ระยะเวลา: ${tempData.start_date} ถึง ${tempData.end_date} (${tempData.days} วัน)\n- เหตุผล: ${tempData.reason}\n\nคำขอได้รับการบันทึกเข้าระบบแล้ว และกำลังรอฝ่ายบุคคล (HR) พิจารณาอนุมัติครับ`
        }];
      }
    } else {
      // Check if we have leave_type but days are depleted
      if (tempData.leave_type) {
        const rem = getRemainingDays(tempData.leave_type);
        if (rem <= 0) {
          responseType = 'direct_reply';
          replyMessages = [{
            "type": "text",
            "text": `⚠️ ไม่สามารถยื่นคำขอลาได้เนื่องจากสิทธิ์วันลาหมดแล้ว\n\n- ประเภทการลา: ${tempData.leave_type_thai}\n- คงเหลือ: 0 วัน`
          }];

          // Automatically append "- bot" to all text responses, and a footer to all Flex bubbles
          if (replyMessages && Array.isArray(replyMessages)) {
            replyMessages.forEach(msg => {
              if (msg.type === 'text') {
                msg.text = msg.text + '\n\n- bot';
              }
            });
          }

          return [{
            json: {
              userId,
              replyToken,
              responseType,
              replyMessages,
              sql: '',
              params: []
            }
          }];
        }
      }

      // Something is missing. Determine the next state to transition to
      let nextState = 'awaiting_leave_type';
      let promptText = 'กรุณาเลือกประเภทการลาที่ต้องการยื่นหยุดงาน:';

      if (!tempData.leave_type) {
        nextState = 'awaiting_leave_type';
        // Show buttons
        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = $2, temp_data = $3::jsonb WHERE line_user_id = $1;`;
        params = [userId, nextState, JSON.stringify(tempData)];

        replyMessages = [{
          "type": "flex",
          "altText": "เลือกประเภทการลาหยุด",
          "contents": {
            "type": "bubble",
            "body": {
              "type": "box",
              "layout": "vertical",
              "contents": [
                { "type": "text", "text": "📝 ยื่นใบลาหยุดงาน", "weight": "bold", "size": "lg", "color": "#4f46e5" },
                { "type": "text", "text": "กรุณาเลือกประเภทการลาเพื่อดำเนินการต่อ:", "size": "sm", "color": "#475569", "margin": "md", "wrap": true },
                { "type": "separator", "margin": "md" },
                {
                  "type": "box",
                  "layout": "vertical",
                  "margin": "md",
                  "spacing": "sm",
                  "contents": [
                    { "type": "button", "action": { "type": "message", "label": "🤒 ลาป่วย (Sick Leave)", "text": "ลาป่วย" }, "style": "primary", "color": "#ef4444" },
                    { "type": "button", "action": { "type": "message", "label": "✈️ ลาพักร้อน (Annual Leave)", "text": "ลาพักร้อน" }, "style": "primary", "color": "#4f46e5" },
                    { "type": "button", "action": { "type": "message", "label": "💼 ลากิจ (Personal Leave)", "text": "ลากิจ" }, "style": "primary", "color": "#f59e0b" },
                    { "type": "button", "action": { "type": "message", "label": "❌ ยกเลิกรายการ", "text": "ยกเลิก" }, "style": "link", "color": "#ef4444" }
                  ]
                }
              ]
            }
          }
        }];
      } else if (!tempData.start_date) {
        nextState = 'awaiting_start_date';
        promptText = `📋 ประเภทการลา: ${tempData.leave_type_thai}\n\nโปรดระบุ "วันที่เริ่มลาหยุด" (เช่น 2026-06-25 หรือพิมพ์ วันนี้ / พรุ่งนี้)`;

        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = $2, temp_data = $3::jsonb WHERE line_user_id = $1;`;
        params = [userId, nextState, JSON.stringify(tempData)];
        replyMessages = [{ "type": "text", "text": promptText }];
      } else if (!tempData.end_date) {
        nextState = 'awaiting_end_date';
        promptText = `📋 ประเภทการลา: ${tempData.leave_type_thai}\n📅 วันเริ่มลา: ${tempData.start_date}\n\nโปรดระบุ "วันที่สิ้นสุด" (เช่น 2026-06-26 หรือพิมพ์จำนวนวัน เช่น 3 วัน)`;

        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = $2, temp_data = $3::jsonb WHERE line_user_id = $1;`;
        params = [userId, nextState, JSON.stringify(tempData)];
        replyMessages = [{ "type": "text", "text": promptText }];
      } else if (!tempData.reason) {
        nextState = 'awaiting_reason';
        promptText = `📋 ประเภทการลา: ${tempData.leave_type_thai}\n📅 ระยะเวลาลา: ${tempData.start_date} ถึง ${tempData.end_date} (${tempData.days} วัน)\n\nโปรดระบุ "เหตุผลการลา" (เช่น พักผ่อนส่วนตัว / เป็นไข้หวัด)`;

        responseType = 'execute_sql';
        sql = `UPDATE user_sessions SET current_state = $2, temp_data = $3::jsonb WHERE line_user_id = $1;`;
        params = [userId, nextState, JSON.stringify(tempData)];
        replyMessages = [{ "type": "text", "text": promptText }];
      }
    }
  }
  else if (nlp.intent === 'check_leave') {
    // Trigger case 6: Check Remaining Leave
    responseType = 'direct_reply';
    const sickRem = input.total_sick_leave - input.used_sick_leave;
    const annualRem = input.total_annual_leave - input.used_annual_leave;
    const personalRem = input.total_personal_leave - input.used_personal_leave;

    replyMessages = [{
      "type": "flex",
      "altText": "วันลาคงเหลือของคุณ",
      "contents": {
        "type": "bubble",
        "body": {
          "type": "box",
          "layout": "vertical",
          "contents": [
            { "type": "text", "text": "📊 วันลาคงเหลือของคุณ", "weight": "bold", "size": "lg", "color": "#10b981" },
            { "type": "text", "text": `คุณ ${input.name}`, "size": "xs", "color": "#94a3b8", "margin": "xs" },
            { "type": "separator", "margin": "sm" },
            { 
              "type": "box", "layout": "vertical", "margin": "md", "contents": [
                { "type": "text", "text": `🤒 ลาป่วย: คงเหลือ ${sickRem} จาก ${input.total_sick_leave} วัน`, "size": "sm", "weight": "bold" },
                { "type": "box", "layout": "vertical", "backgroundColor": "#e2e8f0", "height": "6px", "cornerRadius": "3px", "margin": "xs", "contents": [
                  { "type": "box", "layout": "vertical", "backgroundColor": "#10b981", "height": "6px", "width": `${(sickRem/input.total_sick_leave)*100}%`, "cornerRadius": "3px", "contents": [] }
                ]}
              ] 
            },
            { 
              "type": "box", "layout": "vertical", "margin": "md", "contents": [
                { "type": "text", "text": `✈️ ลาพักร้อน: คงเหลือ ${annualRem} จาก ${input.total_annual_leave} วัน`, "size": "sm", "weight": "bold" },
                { "type": "box", "layout": "vertical", "backgroundColor": "#e2e8f0", "height": "6px", "cornerRadius": "3px", "margin": "xs", "contents": [
                  { "type": "box", "layout": "vertical", "backgroundColor": "#6366f1", "height": "6px", "width": `${(annualRem/input.total_annual_leave)*100}%`, "cornerRadius": "3px", "contents": [] }
                ]}
              ] 
            },
            { 
              "type": "box", "layout": "vertical", "margin": "md", "contents": [
                { "type": "text", "text": `💼 ลากิจ: คงเหลือ ${personalRem} จาก ${input.total_personal_leave} วัน`, "size": "sm", "weight": "bold" },
                { "type": "box", "layout": "vertical", "backgroundColor": "#e2e8f0", "height": "6px", "cornerRadius": "3px", "margin": "xs", "contents": [
                  { "type": "box", "layout": "vertical", "backgroundColor": "#f59e0b", "height": "6px", "width": `${(personalRem/input.total_personal_leave)*100}%`, "cornerRadius": "3px", "contents": [] }
                ]}
              ] 
            }
          ]
        }
      }
    }];
  }
  else if (nlp.intent === 'check_jd') {
    // Trigger case 5: Job Description check
    responseType = 'direct_reply';
    replyMessages = [{
      "type": "flex",
      "altText": "ขอบข่ายงาน (Job Description)",
      "contents": {
        "type": "bubble",
        "body": {
          "type": "box",
          "layout": "vertical",
          "contents": [
            { "type": "text", "text": "📋 ขอบข่ายงานของคุณ", "weight": "bold", "size": "lg", "color": "#6366f1" },
            { "type": "text", "text": input.name, "weight": "bold", "size": "md", "margin": "md" },
            { "type": "text", "text": `${input.position} • แผนก ${input.department}`, "size": "xs", "color": "#94a3b8" },
            { "type": "separator", "margin": "md" },
            { "type": "text", "text": input.job_description, "size": "sm", "wrap": true, "margin": "md", "color": "#334155" }
          ]
        }
      }
    }];
  }
  else {
    // Default Help menu
    responseType = 'direct_reply';
    replyMessages = [{
      "type": "text",
      "text": `สวัสดีครับคุณ ${input.name} ตำแหน่ง ${input.position}\nโปรดระบุงานที่ต้องการจากตัวเลือกด้านล่าง:\n\n- พิมพ์ "ลา" เพื่อยื่นใบลาหยุดงาน\n- พิมพ์ "วันลา" เพื่อเช็คสิทธิ์วันลาคงเหลือ\n- พิมพ์ "job description" เพื่อขอดูขอบข่ายงาน\n- พิมพ์ "/switch <รหัสพนักงาน>" เพื่อสลับตัวตน` 
    }];
  }
}
// Automatically append "- bot" to all text responses, and a footer to all Flex bubbles
if (replyMessages && Array.isArray(replyMessages)) {
  replyMessages.forEach(msg => {
    if (msg.type === 'text') {
      msg.text = msg.text + '\n\n- bot';
    } else if (msg.type === 'flex') {
      try {
        const bubble = msg.contents;
        if (bubble && bubble.type === 'bubble') {
          if (!bubble.footer) {
            bubble.footer = {
              "type": "box",
              "layout": "vertical",
              "contents": [
                {
                  "type": "text",
                  "text": "- bot",
                  "size": "xs",
                  "color": "#94a3b8",
                  "align": "end"
                }
              ]
            };
          } else if (bubble.footer.contents) {
            bubble.footer.contents.push({
              "type": "text",
              "text": "- bot",
              "size": "xs",
              "color": "#94a3b8",
              "align": "end"
            });
          }
        }
      } catch (e) {
        console.error('Failed to append bot footer to flex:', e);
      }
    }
  });
}

return [{
  json: {
    userId,
    replyToken,
    responseType,
    replyMessages,
    sql,
    params
  }
}];
